return ['x-generator'=>'GlotPress/4.0.0-rc.1','translation-revision-date'=>'2025-04-02 15:57:11+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'RocketGenius - Gravity Forms reCAPTCHA','language'=>'pt','messages'=>['You have reached the quota limit for reCAPTCHA set by Google. Please check the quota on your %sreCAPTCHA Account%s.'=>'Atingiu o limite da quota reCAPTCHA definida pelo Google. Verifique a quota na sua %sconta reCAPTCHA%s.','Value defined using the %s constant.'=>'Valor definido pela constante %s.','Click here to learn more about reCAPTCHA.'=>'Clique para saber mais sobre o reCAPTCHA.','Score'=>'Pontuação','reCAPTCHA'=>'reCAPTCHA','reCAPTCHA Score'=>'Pontuação de reCAPTCHA','Disable reCAPTCHA v3 for this form.'=>'Desactivar reCAPTCHA v3 para este formulário.','Score threshold must be between 0.0 and 1.0'=>'A fasquia da pontuação tem de estar entre 0.0 e 1.0','Unexpected field type.'=>'Tipo de campo inesperado.','The default threshold is 0.5.'=>'A fasquia por omissão é 0.5.','If the score is less than or equal to this threshold, the form submission will be sent to spam.'=>'Se a pontuação for inferior ou igual à fasquia, o formulário será enviado para o spam.','reCAPTCHA v3 returns a score (1.0 is very likely a good interaction, 0.0 is very likely a bot).'=>'O reCAPTHA v3 devolve uma pontuação (1.0 é quase de certeza uma boa interacção, 0.0 é mais provável que seja um bot).','check out our documentation.'=>'consulte a nossa documentação.','For more information on reCAPTCHA, which version is right for you, and how to add it to your forms,'=>'Para mais informações sobre reCAPTCHA, qual a versão indicada para si, e como adicionar aos seus formulários,','reCAPTCHA v2 (Checkbox) - Requires a user to click a checkbox to indicate that they are not a robot and displays a challenge if the activity is suspicious'=>'reCAPTCHA v2 (Caixa de selecção) - Requer que o utilizador seleccione uma caixa de selecção para indicar que não é um robô e mostra um desafio se a actividade for suspeita','Read more about reCAPTCHA.'=>'Leia mais sobre o reCAPTCHA.','To activate reCAPTCHA v2 on your form, simply add the CAPTCHA field in the form editor.'=>'Para activar o reCAPTCHA v2 no seu formulário, basta adicionar o campo de CAPTCHA no editor do formulário.','Please note, only v2 keys are supported and checkbox keys are not compatible with invisible reCAPTCHA.'=>'Por favor, tenha em conta que apenas a chave v2 é suportada e as chaves de caixa de selecção não são compatíveis com o reCAPTCHA invisível. ','reCAPTCHA v2 (Invisible) - Displays a badge on your form and will present a challenge to the user if the activity is suspicious e.g. select the traffic lights.'=>'reCAPTCHA v2 (Invisível) - Mostra um distintivo no seu formulário e um desafio ao utilizador se a actividade for suspeita, por exemplo, seleccionar semáforos.','When reCAPTCHA v3 is configured, it is enabled automatically on all forms by default. It can be disabled for specific forms in the form settings.'=>'O reCAPTCHA v3 é activado automaticamente em todos os formulários quando é configurado. Pode ser desactivado caso a caso nas definições de qualquer formulário.','All submissions are accepted and suspicious submissions are marked as spam.'=>'Todas as submissões serão aceites e as submissões suspeitas serão marcadas como spam.','reCAPTCHA v3 - Adds a script to every page of your site and uploads form content for processing by Google.'=>'reCAPTCHA v3 - Adiciona um script a todas as páginas do seu site e carrega o conteúdo do formulário para processamento da Google.','Gravity Forms integrates with three types of Google reCAPTCHA.'=>'O Gravity Forms integra-se com três tipos de Google reCAPTCHA.','By adding reCAPTCHA to your forms, you can deter automated software from submitting form entries, while still ensuring a user-friendly experience for real people.'=>'Ao adicionar reCAPTCHA aos seus formulários, pode impedir softwares de fazerem submissões automatizadas, mantendo uma experiência de utilização agradável para visitantes reais.','Google reCAPTCHA is a free anti-spam service that protects your website from fraud and abuse.'=>'O Google reCAPTCHA é um serviço de anti-spam gratuito que protege o seu site de fraudes e abusos.','reCAPTCHA keys are invalid.'=>'As chaves de reCAPTCHA são inválidas.','Validate Keys'=>'Validar chave','Invisible'=>'Invisível','Checkbox'=>'Caixa de selecção','Type'=>'Tipo','reCAPTCHA v2'=>'reCAPTCHA v2','I have added the reCAPTCHA branding, terms of service and privacy policy to my site. '=>'Adicionei o branding do reCAPTCHA, termos de serviço e política de privacidade ao meu site.','By default reCAPTCHA v3 displays a badge on every page of your site with links to the Google terms of service and privacy policy. You are allowed to hide the badge as long as you include the reCAPTCHA branding and links visibly in the user flow.'=>'Por omissão, o reCAPTCHA v3 mostra um distintivo em cada página do seu site, com ligações para os termos de serviço e política de privacidade da Google. Pode esconder o distintivo desde que inclua o branding do reCAPTCHA e as ligações visíveis no fluxo do utilizador.','Disable Google reCAPTCHA Badge'=>'Desactivar o distintivo do Google reCAPTCHA','Score Threshold'=>'Fasquia da pontuação','Secret Key'=>'Chave secreta','Site Key'=>'Chave do site','reCAPTCHA Settings'=>'Definições do reCAPTCHA','Gravity Forms'=>'Gravity Forms','Enhance Gravity Forms with support for Google reCAPTCHA.'=>'Melhore o Gravity Forms com o suporte para o Google reCAPTCHA.','https://gravityforms.com'=>'https://gravityforms.com','Gravity Forms reCAPTCHA Add-On'=>'Gravity Forms reCAPTCHA Add-On']];